// OmniDesk возвращает объект: {"0": {"case": {...}}, "1": {"case": {...}}, ...}
const response = $input.first().json;

// Проверяем на Cloudflare challenge
if (typeof response === 'string' && response.includes('challenge')) {
  throw new Error('Cloudflare challenge detected. Need to whitelist IP or use different approach.');
}

// Дата отсечки - 7 дней назад
const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - 7);

// Конвертируем объект с числовыми ключами в массив
const tickets = [];
const keys = Object.keys(response).filter(k => !isNaN(parseInt(k)));

console.log(`Found ${keys.length} cases in response`);

for (const key of keys) {
  const caseData = response[key].case || response[key];

  // Парсим дату создания
  let createdAt;
  try {
    createdAt = new Date(caseData.created_at);
  } catch (e) {
    console.log(`Cannot parse date for case ${caseData.case_id}`);
    continue;
  }

  // Фильтруем по дате (только за последние 7 дней)
  if (createdAt >= cutoffDate) {
    tickets.push({
      ticket_id: caseData.case_id,
      case_number: caseData.case_number,
      created_at: caseData.created_at,
      closed_at: caseData.closed_at !== '-' ? caseData.closed_at : null,
      updated_at: caseData.updated_at,
      status: caseData.status,
      priority: caseData.priority,
      channel: caseData.channel,
      subject: caseData.subject,
      user_id: caseData.user_id,
      staff_id: caseData.staff_id,
      group_id: caseData.group_id,
      labels: caseData.labels || [],
      closing_speed: caseData.closing_speed !== '-' ? parseInt(caseData.closing_speed) : null
    });
  }
}

console.log(`Filtered to ${tickets.length} tickets from last 7 days`);

// Возвращаем каждый тикет как отдельный item
return tickets.map(ticket => ({ json: ticket }));
